export const clientIdResolver = {
    type: "dynamic",
    fetch: async (sdk) => {
        const result = await sdk.listClientCredentials({ maxItems: 100 });
        return result.data;
    },
    prompt: (credentials) => ({
        type: "list",
        name: "clientId",
        message: "Select client credentials to delete:",
        choices: credentials.map((cred) => ({
            name: `${cred.name} (${cred.client_id})`,
            value: cred.client_id,
        })),
    }),
};
